// Build ONE timestamped HistoryState-shaped record from the current portfolio.
// OmniProject stores nothing; this record is written to the operator's logging
// store, which IS the durable history. Egressed data is outside OmniProject's
// warranty — the operator owns this destination.
const rows = items.map((i) => i.json);
const portfolio = Array.isArray(rows) && rows.length === 1 && Array.isArray(rows[0]) ? rows[0] : rows;
const list = Array.isArray(portfolio) ? portfolio : (portfolio.data ?? portfolio.projects ?? [portfolio]);

const pct = (p) => Number(p.completionPct ?? p.completionPercentage ?? p.percentComplete ?? 0);
const blockers = (p) => Number(p.activeBlockersCount ?? p.openBlockers ?? 0);

const n = list.length || 1;
const completionPct = Math.round(list.reduce((s, p) => s + pct(p), 0) / n);
const openBlockers = list.reduce((s, p) => s + blockers(p), 0);

return [{ json: {
  at: new Date().toISOString(),
  completionPct,
  openBlockers,
  provenance: 'replayed',
  source: 'omniproject-historian'
} }];

// Map the operator logging store's rows into the HistoryState[] contract the
// gateway expects: { at, completionPct, openBlockers, provenance }. Recorded
// states are 'replayed' (real, not projected). Window-filter as a backstop in
// case the store ignored from/to.
const body = $('Webhook').first().json.body;
const from = body.payload && body.payload.from ? Date.parse(body.payload.from) : -Infinity;
const to = body.payload && body.payload.to ? Date.parse(body.payload.to) : Infinity;

const rows = items.map((i) => i.json);
const hits = rows.length === 1 && Array.isArray(rows[0]) ? rows[0]
  : (rows.length === 1 && rows[0] && Array.isArray(rows[0].hits)) ? rows[0].hits
  : rows;

const states = (hits || [])
  .map((r) => (r && r._source) ? r._source : r)
  .filter((r) => r && r.at)
  .filter((r) => { const t = Date.parse(r.at); return t >= from && t <= to; })
  .map((r) => ({
    at: new Date(r.at).toISOString(),
    completionPct: Number(r.completionPct ?? 0),
    openBlockers: r.openBlockers == null ? null : Number(r.openBlockers),
    provenance: 'replayed'
  }))
  .sort((a, b) => Date.parse(a.at) - Date.parse(b.at));

return [{ json: { success: true, data: states, message: 'replay ok' } }];
